SELECT SUM(goals_for) AS total_goals_scored
FROM goal_statistics
WHERE team_id = 1 AND season = '2022-2023';

SELECT team_name
FROM teams
ORDER BY team_name;

SELECT AVG(ps.distance_covered) AS average_distance_covered
FROM player_statistics ps
WHERE ps.season = '2022-2023';

SELECT AVG(goal_diff) AS average_goal_difference
FROM goal_statistics
WHERE team_id = 1 AND season = '2022-2023';

SELECT wins, league_position
FROM match_results
WHERE team_id = 1 AND season = '2022-2023';
